, r.REQ_USER_ID , r.REQ_NO , r.PROFILE FROM ( SELECT JOIN_NO , USER_ID , CATEGORY , PARTICIPANTS , REGION , START_DATE , END_DATE , TITLE , CONTENT , DELETED , CREATE_DATE FROM JOIN_BOARD WHERE DELETED = 'N'
